import React, { useEffect, useLayoutEffect, useRef, useState } from 'react';
import { createPortal } from 'react-dom';
import styles from '../../styles/erpPage.module.css';

export type CatalogRowEditHintState = {
  x: number;
  y: number;
  message: string;
};

const VIEWPORT_MARGIN = 8;
const AUTO_DISMISS_MS = 6000;

function clampPosition(
  x: number,
  y: number,
  width: number,
  height: number,
): { left: number; top: number } {
  const vw = window.innerWidth;
  const vh = window.innerHeight;
  let left = x + 12;
  let top = y + 12;
  if (left + width > vw - VIEWPORT_MARGIN) {
    left = Math.max(VIEWPORT_MARGIN, x - width - 12);
  }
  if (top + height > vh - VIEWPORT_MARGIN) {
    top = Math.max(VIEWPORT_MARGIN, y - height - 12);
  }
  return { left, top };
}

export interface CatalogRowEditHintLayerProps {
  hint: CatalogRowEditHintState | null;
  onDismiss: () => void;
}

/** Ephemeral hint anchored near pointer — catalog list readonly row. */
export function CatalogRowEditHintLayer({
  hint,
  onDismiss,
}: CatalogRowEditHintLayerProps): React.ReactElement | null {
  const panelRef = useRef<HTMLDivElement>(null);
  const [position, setPosition] = useState<{ left: number; top: number } | null>(null);

  useLayoutEffect(() => {
    if (!hint) {
      setPosition(null);
      return;
    }
    const rect = panelRef.current?.getBoundingClientRect();
    const w = rect?.width ?? 280;
    const h = rect?.height ?? 48;
    setPosition(clampPosition(hint.x, hint.y, w, h));
  }, [hint]);

  useEffect(() => {
    if (!hint) return;
    const timer = window.setTimeout(onDismiss, AUTO_DISMISS_MS);
    const onKey = (e: KeyboardEvent) => {
      if (e.key === 'Escape') onDismiss();
    };
    const onPointer = () => onDismiss();
    document.addEventListener('keydown', onKey);
    document.addEventListener('mousedown', onPointer);
    document.addEventListener('touchstart', onPointer, { passive: true });
    return () => {
      window.clearTimeout(timer);
      document.removeEventListener('keydown', onKey);
      document.removeEventListener('mousedown', onPointer);
      document.removeEventListener('touchstart', onPointer);
    };
  }, [hint, onDismiss]);

  if (!hint) return null;

  const style: React.CSSProperties = position
    ? { left: position.left, top: position.top }
    : { left: hint.x + 12, top: hint.y + 12, visibility: 'hidden' as const };

  return createPortal(
    <div
      ref={panelRef}
      className={styles.catalogRowEditHint}
      style={style}
      role="status"
      aria-live="polite"
      onMouseDown={e => e.stopPropagation()}
    >
      <i className="fas fa-lock" aria-hidden />
      <span>{hint.message}</span>
    </div>,
    document.body,
  );
}
