import React from 'react';
import { InfoHint, useDeviceContentSize } from '@linm-soft/common-components';
import styles from '../../styles/erpPage.module.css';

export type CatalogPageHeaderProps = {
  title: React.ReactNode;
  titleIconClass?: string;
  /** Desktop: subtitle block · Mobile: tooltip on info icon only */
  hint?: React.ReactNode;
  /** Plain text for tooltip (required on mobile if hint has rich markup) */
  hintTooltip?: string;
};

export function CatalogPageHeader({
  title,
  titleIconClass = 'fas fa-folder',
  hint,
  hintTooltip,
}: CatalogPageHeaderProps): React.ReactElement {
  const { isSmall } = useDeviceContentSize();
  const isMobileLayout = isSmall;
  const tipText = hintTooltip?.trim();

  return (
    <div className={styles.pageHeader}>
      <div className={styles.titleBlock}>
        <h1 className={styles.title}>
          <i className={titleIconClass} aria-hidden />
          {title}
          {isMobileLayout && tipText ? (
            <InfoHint content={tipText} className={styles.catalogPageHintBtn} />
          ) : null}
        </h1>
        {!isMobileLayout && hint ? (
          <div className={styles.subtitle}>{hint}</div>
        ) : null}
      </div>
    </div>
  );
}
