import React, { useState } from 'react';
import { Button, useDeviceContentSize } from '@linm-soft/common-components';
import { AnchoredDropdown } from './AnchoredDropdown';
import styles from '../../styles/erpPage.module.css';

export type CatalogListHeaderFiltersProps = {
  testIdPrefix: string;
  children: React.ReactNode;
};

/** Desktop: filters in grid header · Mobile: icon only → modal dropdown */
export function CatalogListHeaderFilters({
  testIdPrefix,
  children,
}: CatalogListHeaderFiltersProps): React.ReactElement {
  const { isSmall } = useDeviceContentSize();
  const [open, setOpen] = useState(false);

  if (!isSmall) {
    return <>{children}</>;
  }

  return (
    <AnchoredDropdown
      isOpen={open}
      onClose={() => setOpen(false)}
      width="full"
      dropdownTestId={`${testIdPrefix}-filter-dropdown`}
      anchor={(
        <Button
          variant="secondary"
          size="sm"
          className={styles.catalogGridFilterBtn}
          aria-label="Bộ lọc"
          data-testid={`${testIdPrefix}-filter-btn`}
          onClick={() => setOpen(v => !v)}
        >
          <i className="fas fa-filter" />
        </Button>
      )}
    >
      <div className={styles.anchoredDropdownBody}>{children}</div>
      <div className={styles.anchoredDropdownActions}>
        <Button variant="secondary" onClick={() => setOpen(false)}>
          Đóng
        </Button>
      </div>
    </AnchoredDropdown>
  );
}
