import type { CatalogListHeightMode, CatalogUiListOptions } from '../../types/catalogUiSchema';

export type CatalogListTableConfig = {
  stickyHeader: boolean;
  heightMode: CatalogListHeightMode;
  height: string | null;
  resizable: boolean;
};

export const DEFAULT_CATALOG_LIST_TABLE_CONFIG: CatalogListTableConfig = {
  stickyHeader: true,
  heightMode: 'auto',
  height: null,
  resizable: true,
};

export function catalogListTableConfigFromSchema(
  list?: CatalogUiListOptions | null,
): CatalogListTableConfig {
  return {
    stickyHeader: list?.stickyHeader ?? DEFAULT_CATALOG_LIST_TABLE_CONFIG.stickyHeader,
    heightMode: list?.heightMode ?? DEFAULT_CATALOG_LIST_TABLE_CONFIG.heightMode,
    height: list?.height ?? DEFAULT_CATALOG_LIST_TABLE_CONFIG.height,
    resizable: list?.resizableColumns ?? DEFAULT_CATALOG_LIST_TABLE_CONFIG.resizable,
  };
}

/** Parse list.width (8rem, 120px, minmax(12rem, 1fr)) → px for resize baseline. */
export function parseCatalogColumnWidthPx(width?: string | null): number | undefined {
  if (!width?.trim()) return undefined;
  const w = width.trim();
  const rem = w.match(/^([\d.]+)rem$/);
  if (rem) return Math.round(parseFloat(rem[1]) * 16);
  const px = w.match(/^([\d.]+)px$/);
  if (px) return Math.round(parseFloat(px[1]));
  const minmax = w.match(/minmax\(\s*([\d.]+)rem/i);
  if (minmax) return Math.round(parseFloat(minmax[1]) * 16);
  return undefined;
}
