import React, { useCallback, useEffect, useMemo, useRef, useState } from 'react';
import { createPortal } from 'react-dom';
import styles from '../../styles/erpPage.module.css';

export type AnchoredDropdownProps = {
  anchor: React.ReactElement;
  isOpen: boolean;
  onClose: () => void;
  width?: number | 'anchor' | 'auto' | 'full';
  children: React.ReactNode;
  dropdownTestId?: string;
};

function clamp(n: number, min: number, max: number): number {
  return Math.max(min, Math.min(max, n));
}

export function AnchoredDropdown({
  anchor,
  isOpen,
  onClose,
  width = 'anchor',
  children,
  dropdownTestId,
}: AnchoredDropdownProps): React.ReactElement {
  const anchorRef = useRef<HTMLSpanElement | null>(null);
  const dropdownRef = useRef<HTMLDivElement | null>(null);
  const [pos, setPos] = useState<React.CSSProperties>({});

  const recompute = useCallback(() => {
    const rect = anchorRef.current?.getBoundingClientRect();
    if (!rect) return;

    const pad = 8;
    const maxW = window.innerWidth - pad * 2;
    const desiredW =
      typeof width === 'number'
        ? width
        : width === 'full'
          ? maxW
        : width === 'auto'
          ? 280
          : rect.width;
    const w = clamp(desiredW, 160, maxW);

    const left = width === 'full'
      ? pad
      : clamp(rect.left, pad, window.innerWidth - pad - w);
    const top = rect.bottom + 6;

    setPos({
      position: 'fixed',
      left,
      top,
      width: w,
      zIndex: 1200,
    });
  }, [width]);

  useEffect(() => {
    if (!isOpen) return;
    recompute();
    const onKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'Escape') onClose();
    };
    const onPointerDown = (e: PointerEvent) => {
      const t = e.target as Node | null;
      if (!t) return;
      if (anchorRef.current?.contains(t)) return;
      if (dropdownRef.current?.contains(t)) return;
      onClose();
    };

    window.addEventListener('scroll', recompute, true);
    window.addEventListener('resize', recompute);
    window.addEventListener('keydown', onKeyDown);
    window.addEventListener('pointerdown', onPointerDown);
    return () => {
      window.removeEventListener('scroll', recompute, true);
      window.removeEventListener('resize', recompute);
      window.removeEventListener('keydown', onKeyDown);
      window.removeEventListener('pointerdown', onPointerDown);
    };
  }, [isOpen, onClose, recompute]);

  const anchorNode = useMemo(() => {
    return (
      <span ref={anchorRef} className={styles.anchoredDropdownAnchor}>
        {anchor}
      </span>
    );
  }, [anchor]);

  return (
    <>
      {anchorNode}
      {isOpen
        ? createPortal(
            <div
              ref={dropdownRef}
              className={styles.anchoredDropdownPanel}
              style={pos}
              data-testid={dropdownTestId}
              role="dialog"
            >
              {children}
            </div>,
            document.body,
          )
        : null}
    </>
  );
}

