import { useCallback, useEffect, useMemo, useState } from 'react';

import { dispatchAppToast } from '@linm-soft/common-components';

import { useAppDispatch } from '../store/hooks';

import { masterService } from '../services/master/masterService';

import type { SharedCatalogMetaDto, TenantCatalogRow } from '../services/master/models';

import type { SharedCatalogListMeta } from '../components/catalog/SharedCatalogListFooter';

import type { SharedCatalogProposalSubmitChange } from '../components/catalog/SharedCatalogProposalModal';

import { buildSharedCatalogChangePayloadJson } from '../utils/sharedCatalogProposalPayload';



export type SharedCatalogScope = NonNullable<TenantCatalogRow['scope']>;



export function isSharedCatalogReadOnly(row: {

  isReadOnly?: boolean;

  scope?: string;

}): boolean {

  return !!row.isReadOnly || row.scope === 'Shared' || row.scope === 'System';

}



export interface SharedCatalogChangeRequestBody {

  catalogKind: string;

  action: 'Create' | 'Update' | 'Delete';

  entityKey: string;

  payloadJson?: string;

}



export interface UseSharedCatalogResult {

  meta: SharedCatalogMetaDto | null;

  listMeta: SharedCatalogListMeta | null;

  usageActive: boolean;

  canRequest: boolean;

  requesting: boolean;

  approvalOpen: boolean;

  setApprovalOpen: (open: boolean) => void;

  handleRequestUsage: (note?: string) => Promise<void>;

  handleCreateChangeRequest: (body: SharedCatalogChangeRequestBody) => Promise<void>;

  handleSubmitProposalChange: (

    entityKey: string,

    submit: SharedCatalogProposalSubmitChange,

  ) => Promise<void>;

  handleReviewed: () => Promise<void>;

  reloadMeta: () => Promise<void>;

}



export function useSharedCatalog(

  catalogKind: string,

  onRefresh?: () => void,

): UseSharedCatalogResult {

  const dispatch = useAppDispatch();

  const [meta, setMeta] = useState<SharedCatalogMetaDto | null>(null);

  const [requesting, setRequesting] = useState(false);

  const [approvalOpen, setApprovalOpen] = useState(false);



  const reloadMeta = useCallback(async () => {

    try {

      const m = await masterService.getSharedCatalogMeta(catalogKind);

      setMeta(m);

    } catch {

      /* optional meta — non-blocking */

    }

  }, [catalogKind]);



  useEffect(() => {

    let cancelled = false;

    const t = setTimeout(() => {

      masterService

        .getSharedCatalogMeta(catalogKind)

        .then(m => { if (!cancelled) setMeta(m); })

        .catch(() => { /* optional */ });

    }, 0);

    return () => { cancelled = true; clearTimeout(t); };

  }, [catalogKind]);



  const listMeta = useMemo<SharedCatalogListMeta | null>(

    () =>

      meta

        ? {

            usageStatus: meta.usageStatus,

            canRequest: meta.canRequest,

            canApprove: meta.canApprove,

          }

        : null,

    [meta],

  );



  const usageActive = meta?.usageStatus === 'Active';

  const canRequest = !!meta?.canRequest;



  const handleRequestUsage = useCallback(async (note?: string) => {

    setRequesting(true);

    try {

      await masterService.requestSharedCatalogUsage(catalogKind, note);

      dispatchAppToast(dispatch, { message: 'Đã gửi đề xuất sử dụng danh mục chung', type: 'success' });

      await reloadMeta();

      onRefresh?.();

    } catch (err: unknown) {

      dispatchAppToast(dispatch, {

        message: err instanceof Error ? err.message : 'Gửi đề xuất thất bại',

        type: 'error',

      });

      throw err;

    } finally {

      setRequesting(false);

    }

  }, [catalogKind, dispatch, onRefresh, reloadMeta]);



  const handleCreateChangeRequest = useCallback(

    async (body: SharedCatalogChangeRequestBody) => {

      await masterService.createSharedCatalogChangeRequest(body);

      const actionLabel =

        body.action === 'Create' ? 'đưa vào dùng chung' : body.action === 'Update' ? 'sửa' : 'xóa';

      dispatchAppToast(dispatch, { message: `Đã gửi đề xuất ${actionLabel} — chờ duyệt`, type: 'success' });

    },

    [dispatch],

  );



  const handleSubmitProposalChange = useCallback(

    async (entityKey: string, submit: SharedCatalogProposalSubmitChange) => {

      await handleCreateChangeRequest({

        catalogKind,

        action: submit.action,

        entityKey,

        payloadJson: buildSharedCatalogChangePayloadJson(submit),

      });

      onRefresh?.();

    },

    [catalogKind, handleCreateChangeRequest, onRefresh],

  );



  const handleReviewed = useCallback(async () => {

    await reloadMeta();

    onRefresh?.();

  }, [onRefresh, reloadMeta]);



  return {

    meta,

    listMeta,

    usageActive,

    canRequest,

    requesting,

    approvalOpen,

    setApprovalOpen,

    handleRequestUsage,

    handleCreateChangeRequest,

    handleSubmitProposalChange,

    handleReviewed,

    reloadMeta,

  };

}

